// LESSON: Queue Deque PriorityQueue - Reference Page 2.
// You will learn: Choose Queue, Deque, and PriorityQueue operations for ordered work.
import java.util.ArrayDeque;
import java.util.HashSet;
import java.util.PriorityQueue;
import java.util.Queue;
import java.util.Deque;
import java.util.Set;

class QueueDequePriorityQueueReference {
  public static void main(String[] args) {
    example1QueueFifo();
    example2DequeEndsAndStack();
    example3PriorityQueueOrder();
    example4BfsFrontier();
  }

  static void example1QueueFifo() {
    Queue<String> line = new ArrayDeque<>();
    line.offer("Ana");
    line.offer("Bo");
    String next = line.peek();
    String served = line.poll();
    String afterServing = line.poll();
    System.out.println(next + " " + served + " " + afterServing);
  }

  static void example2DequeEndsAndStack() {
    Deque<String> deque = new ArrayDeque<>();
    deque.addFirst("front");
    deque.addLast("back");
    String first = deque.peekFirst();
    String last = deque.peekLast();
    deque.push("top");
    String popped = deque.pop();
    System.out.println(first + " " + last + " " + popped);
  }

  static void example3PriorityQueueOrder() {
    PriorityQueue<Integer> tasks = new PriorityQueue<>();
    tasks.offer(3);
    tasks.offer(1);
    tasks.offer(2);
    System.out.println(tasks.peek());
    while (!tasks.isEmpty()) {
      int priority = tasks.poll();
      System.out.println(priority);
    }
  }

  static void example4BfsFrontier() {
    Queue<String> frontier = new ArrayDeque<>();
    Set<String> visited = new HashSet<>();
    frontier.offer("Start");
    while (!frontier.isEmpty()) {
      String node = frontier.poll();
      if (visited.add(node)) {
        System.out.println("Visited " + node);
        if (node.equals("Start")) {
          frontier.offer("A");
          frontier.offer("B");
        }
      }
    }
  }
}
